    "TMP57_3_03": ["У вас есть 4 мешка по 2 яблока в каждом. Сколько там яблок?", "Посчитайте от 2 до 2: 2, 4, 6, 8. Или сложите: 2+2+2+2.", ["6", "10", "8", "4"], "4 пакетика по 2 яблока: 2+2+2+2=8 яблок!"],
    "TMP57_3_04": ["Если у 5 птиц по две ноги, сколько всего ног?", "Сосчитайте от 2 до 2 пять раз: 2, 4, 6, 8, 10.", ["8", "12", "6", "10"], "5 птиц по 2 ноги: 2+2+2+2+2=10 ног!"],
    "TMP57_3_05": ["Если у трех собак по 4 ноги, сколько всего ног?", "Посчитайте от 4 до 4: 4, 8, 12. Или сложите: 4+4+4.", ["12", "8", "10", "6"], "3 собаки по 4 ноги: 4+4+4=12 ног!"],
    "TMP57_3_06": ["У вас есть 2 коробки по 5 карандашей в каждой. Сколько там карандашей?", "Соберите карандаши: 5 + 5.", ["8", "10", "12", "6"], "2 коробки по 5 карандашей в каждой: 5+5=10 карандашей!"],
    "TMP57_3_07": ["Если у четырех детей по два глаза, сколько всего глаз?", "Считаем от 2 до 2: 2, 4, 6, 8.", ["6", "10", "8", "4"], "4 ребенка по 2 глаза: 2+2+2+2=8 глаз!"],
    "TMP57_3_08": ["Если у двух пауков по 8 ног, сколько всего ног?", "Добавляем ножки: 8+8.", ["12", "14", "10", "16"], "2 паука по 8 ног: 8+8=16 ног!"],
    "TMP57_3_09": ["Вы покупаете 3 упаковки наклеек. В каждой упаковке 3 наклейки. Сколько там наклеек?", "Посчитайте от 3 до 3: 3, 6, 9. Или сложите: 3+3+3.", ["9", "6", "12", "8"], "3 упаковки по 3 наклейки: 3+3+3=9 наклеек!"],
    "TMP57_3_10": ["Если в 5 цветках по 4 лепестка, сколько всего лепестков?", "Числа от 4 до 4: 4, 8, 12, 16, 20.", ["15", "20", "25", "10"], "5 цветков по 4 лепестка: 4+4+4+4+4=20 лепестков!"],
    "TMP57_3_11": ["Если у двух велосипедов по два колеса, сколько всего в них колес?", "Добавляем колеса: 2+2.", ["6", "2", "4", "8"], "2 велосипеда по 2 колеса каждый: 2+2=4 колеса!"],
    "TMP57_3_12": ["Если у четырех кошек по 4 ноги, сколько всего ног?", "Числа от 4 до 4: 4, 8, 12, 16.", ["12", "8", "14", "16"], "4 кота по 4 ноги: 4+4+4+4=16 ног!"],
    "TMP57_3_13": ["У вас есть 5 тарелок. На каждой тарелке по 2 печенья. Сколько там печенья?", "Считаем по двое: 2, 4, 6, 8, 10.", ["10", "8", "12", "6"], "5 тарелок по 2 печенья в каждой: 2 + 2 + 2 + 2 + 2 = 10 печенья!"],
    "TMP57_3_14": ["Если у трех трехколесных велосипедов по три колеса, сколько всего в них колес?", "Считаем от 3 до 3: 3, 6, 9.", ["6", "9", "12", "8"], "3 трицикла по 3 колеса: 3+3+3=9 колёс!"],
    "TMP57_3_15": ["Если на двух руках по 5 пальцев, сколько всего пальцев?", "Соедините пальцы: 5+5.", ["8", "12", "10", "5"], "2 руки по 5 пальцев: 5+5=10 пальцев!"],
    "TMP57_3_16": ["У тебя 4 друга. Раздайте каждому другу по 3 конфеты. Сколько конфет вам нужно?", "Считаем от 3 до 3: 3, 6, 9, 12.", ["8", "10", "15", "12"], "4 друга по 3 конфеты: 3 + 3 + 3 + 3 = 12 конфет!"],
    "TMP57_3_17": ["Если у трех столов по 4 ножки каждый, сколько всего ножек?", "Считаем от 4 до 4: 4, 8, 12.", ["12", "8", "10", "16"], "3 стола по 4 ножки каждый: 4+4+4=12 ножек!"],
    "TMP57_3_18": ["Если 5 детей получат по 3 шарика, сколько всего шариков?", "Числа от 3 до 3: 3, 6, 9, 12, 15.", ["12", "15", "18", "10"], "5 детей по 3 шарика: 3+3+3+3+3=15 шариков!"],
    "TMP57_3_19": ["Сколько в них яиц, если в 4 гнездах по 3 яйца?", "Считаем от 3 до 3: 3, 6, 9, 12.", ["8", "10", "12", "9"], "4 гнезда по 3 яйца в каждом: 3+3+3+3=12 яиц!"],
    "TMP57_3_20": ["Если на двух кубиках по 6 граней, сколько всего граней?", "Складываем лиц: 6+6.", ["8", "10", "6", "12"], "2 кубика по 6 граней: 6 + 6 = 12 граней!"],
